  ('aboriginal-f0899a01-moex-00470', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政罰程序之敘述，下列何者錯誤？', '["甲就衛生主管機關對其所為之強制排除抗拒保全證據，不得表示不服", "行政機關基於裁罰之必要，得將可為證據之物予以扣留", "行政機關因作成大量同種類之裁處，於裁處前，得不給予受處罰者陳述意見之機會", "行政罰之裁處不得以言詞為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00471', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於罰鍰與怠金之敘述，下列何者錯誤？', '["同屬公法上金錢給付義務", "罰鍰有一行為不二罰原則之適用，而怠金則無", "處以怠金後，倘義務人已履行義務者，即應終止行政執行程序", "對於罰鍰之救濟，須先聲明異議，不服聲明異議之決定後，再提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00472', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關行政執行之敘述，下列何者錯誤？', '["行政機關對於不履行行政法上義務之義務人以強制手段促使其履行義務", "行政執行包括金錢給付義務、行為或不行為義務之執行與即時強制", "即時強制須先以下命處分課予人民義務", "行政執行係為實現下命處分要求之內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
